                                                { l: 'Rear Wing', v: sel.setupData.rearWing, u: '' },
                                                { l: 'Diff On Throttle', v: sel.setupData.diffOnThrottle, u: '%' },
                                                { l: 'Diff Off Throttle', v: sel.setupData.diffOffThrottle, u: '%' },
