                                                { l: 'Brake Bias', v: sel.setupData.brakeBias, u: '%' },
                                                { l: 'Front Tyre Psi', v: sel.setupData.frontTyrePressure, u: 'psi' },
                                                { l: 'Rear Tyre Psi', v: sel.setupData.rearTyrePressure, u: 'psi' },
