            )}

            {/* Lap Time */}
            <div className="mb-6">
                <label className="block text-xs font-sora font-semibold mb-2">Lap Time</label>
                <input
                    type="text"
                    value={lapTime}
                    onChange={e => setLapTime(e.target.value)}
